// src/components/auth/Signup/Signup.jsx
import { useState } from 'react';
import { Link } from 'react-router-dom';
import StudentForm from './forms/StudentForm';
import InstructorForm from './forms/InstructorForm';
import './index.css';

export default function Signup() {
  const [role, setRole] = useState('student');

  return (
    <div className="signup-page">

      <div className="signup-container">

        {/* Logo + Title */}
        <div className="logo-section">
          <svg className="logo-icon" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="m8 3 4 8 5-5 5 15H2L8 3z" />
          </svg>
          <p className="app-name">TunisiaED</p>
        </div>

        {/* Heading */}
        <div className="title-section">
          <h1 className="main-title">Create Your Account</h1>
          <p className="subtitle">Start your journey with TunisiaED</p>
        </div>

        {/* Role Toggle */}
        <div className="role-toggle">
          <div className={`slider ${role === 'instructor' ? 'instructor' : ''}`} />
          <button
            type="button"
            onClick={() => setRole('student')}
            className={role === 'student' ? 'active' : ''}
          >
            Sign up as a Student
          </button>
          <button
            type="button"
            onClick={() => setRole('instructor')}
            className={role === 'instructor' ? 'active' : ''}
          >
            Sign up as an Instructor
          </button>
        </div>

        {/* Forms */}
        <div className="forms-wrapper">
          <div className={`form-slide ${role === 'student' ? 'active' : ''}`}>
            <StudentForm />
          </div>
          <div className={`form-slide ${role === 'instructor' ? 'active' : ''}`}>
            <InstructorForm />
          </div>
        </div>

        {/* Login link */}
        <p className="login-link">
          Already have an account?{' '}
          <Link to="/login" className="login-link-text">Login</Link>
        </p>

      </div>
    </div>
  );
}
